import React, { useState } from "react";
import { createClient } from "@supabase/supabase-js";
import { motion } from "framer-motion";
import { Truck, PackageSearch, ShieldCheck, Loader2, Eye, EyeOff, LogIn } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";

/**
 * ⚠️ Security Note
 * This component preserves your existing table-based credential check for compatibility.
 * For production, prefer Supabase Auth (email/password) instead of querying a "Login" table.
 * See the commented "Alternative: Supabase Auth" block inside handleLogin.
 */

const supabase = createClient(
    import.meta.env.VITE_SUPABASE_URL || process.env.REACT_APP_SUPABASE_URL,
    import.meta.env.VITE_SUPABASE_KEY || process.env.REACT_APP_SUPABASE_KEY
);

export default function Login({ onLoginSuccess }) {
    const [email, setEmail] = useState(""); // kullanici_adi
    const [password, setPassword] = useState(""); // sifre
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [showPassword, setShowPassword] = useState(false);

    const handleLogin = async (e) => {
        e.preventDefault();
        setError("");
        setLoading(true);

        try {
            // --- Existing: Table-based auth (kept for backward compatibility)
            const { data, error } = await supabase
                .from("Login")
                .select("*")
                .eq("kullanici_adi", email)
                .eq("sifre", password)
                .single();

            if (error || !data) {
                setError("Hatalı kullanıcı adı veya şifre.");
                return;
            }

            // ✅ Tüm kullanıcı kaydını sakla
            localStorage.setItem("kullanici", JSON.stringify(data));

            // ✅ REEL bilgilerini esnek alan adlarıyla yakala
            const reelUser =
                data.Reel_kullanici ??
                data.reel_kullanici ??
                data.reelUserName ??
                data.reel_username ??
                "";
            const reelPass =
                data.Reel_sifre ??
                data.reel_sifre ??
                data.reelPassword ??
                data.reel_password ??
                "";

            if (reelUser) localStorage.setItem("Reel_kullanici", reelUser);
            if (reelPass) localStorage.setItem("Reel_sifre", reelPass);

            if (reelUser && reelPass) {
                localStorage.setItem(
                    "reelCreds",
                    JSON.stringify({ userName: reelUser, password: reelPass })
                );
            } else {
                console.warn(
                    "[REEL] Giriş kaydında Reel_kullanici / Reel_sifre alanları bulunamadı."
                );
            }

            onLoginSuccess?.();

            // --- Alternative: Supabase Auth (recommended)
            // const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
            //   email,
            //   password,
            // });
            // if (authError) {
            //   setError(authError.message);
            //   return;
            // }
            // // authData.session.access_token vb. burada kullanılabilir
            // onLoginSuccess?.();
        } catch (err) {
            console.error(err);
            setError("Beklenmeyen bir hata oluştu. Lütfen tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen w-full bg-slate-950 relative overflow-hidden">
            {/* Background grid + accents */}
            <BackgroundDecor />

            <div className="relative z-10 mx-auto flex min-h-screen w-full max-w-7xl flex-col items-center justify-center px-6 py-10 lg:flex-row lg:gap-12">
                {/* Brand / Hero */}
                <motion.section
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.6 }}
                    className="text-center lg:text-left lg:w-1/2"
                >
                    <div className="inline-flex items-center gap-3 rounded-full border border-white/10 bg-white/5 px-4 py-2 backdrop-blur">
                        <Truck className="h-4 w-4" />
                        <span className="text-xs tracking-wide text-slate-200">LogiPro · Lojistik Operasyon Platformu</span>
                    </div>

                    <h1 className="mt-6 text-4xl font-bold leading-tight tracking-tight text-white sm:text-5xl">
                        Akıllı Lojistik için <span className="text-sky-400">güvenli</span> giriş
                    </h1>
                    <p className="mt-3 max-w-xl text-slate-300">
                        Depo, filo ve sevkiyat süreçlerinizi tek panelden yönetin. Gerçek zamanlı
                        takip, dinamik rota optimizasyonu ve uçtan uca görünürlük.
                    </p>

                    <ul className="mt-6 grid grid-cols-1 gap-3 sm:grid-cols-2">
                        <Feature icon={PackageSearch} title="Canlı Takip" desc="Araç & kargo konumları" />
                        <Feature icon={ShieldCheck} title="Kurumsal Güvenlik" desc="Rol tabanlı erişim" />
                    </ul>
                </motion.section>

                {/* Login Card */}
                <motion.section
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.6, delay: 0.1 }}
                    className="mt-10 w-full lg:mt-0 lg:w-1/2"
                >
                    <Card className="mx-auto w-full max-w-md border-white/10 bg-white/5 backdrop-blur-md">
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2 text-white">
                                <LogIn className="h-5 w-5" /> Giriş Yap
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <form onSubmit={handleLogin} className="space-y-5">
                                <div className="space-y-2">
                                    <Label htmlFor="email" className="text-slate-200">Kullanıcı Adı</Label>
                                    <Input
                                        id="email"
                                        type="text"
                                        placeholder="kullanici_adi"
                                        value={email}
                                        onChange={(e) => setEmail(e.target.value)}
                                        autoComplete="username"
                                        required
                                        className="bg-white/10 text-white placeholder:text-slate-400 border-white/10"
                                    />
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="password" className="text-slate-200">Şifre</Label>
                                    <div className="relative">
                                        <Input
                                            id="password"
                                            type={showPassword ? "text" : "password"}
                                            placeholder="••••••••"
                                            value={password}
                                            onChange={(e) => setPassword(e.target.value)}
                                            autoComplete="current-password"
                                            required
                                            className="bg-white/10 text-white placeholder:text-slate-400 border-white/10 pr-10"
                                        />
                                        <button
                                            type="button"
                                            aria-label={showPassword ? "Şifreyi gizle" : "Şifreyi göster"}
                                            onClick={() => setShowPassword((s) => !s)}
                                            className="absolute inset-y-0 right-0 flex items-center pr-3 text-slate-300 hover:text-white"
                                        >
                                            {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                        </button>
                                    </div>
                                </div>

                                {error && (
                                    <p className="rounded-md border border-red-400/30 bg-red-500/10 px-3 py-2 text-sm text-red-300">
                                        {error}
                                    </p>
                                )}

                                <Button
                                    type="submit"
                                    disabled={loading}
                                    className="w-full bg-sky-500 text-white hover:bg-sky-400"
                                >
                                    {loading ? (
                                        <span className="inline-flex items-center gap-2">
                                            <Loader2 className="h-4 w-4 animate-spin" /> Giriş yapılıyor…
                                        </span>
                                    ) : (
                                        "Giriş"
                                    )}
                                </Button>

                                <p className="text-center text-xs text-slate-400">
                                    Devam ederek <a className="underline underline-offset-4 hover:text-slate-200" href="#">Kullanım Koşullarını</a> kabul etmiş olursunuz.
                                </p>
                            </form>
                        </CardContent>
                    </Card>
                </motion.section>
            </div>
        </div>
    );
}

function Feature({ icon: Icon, title, desc }) {
    return (
        <div className="flex items-start gap-3 rounded-2xl border border-white/10 bg-white/5 p-4">
            <div className="rounded-xl bg-sky-500/20 p-2 text-sky-300">
                <Icon className="h-5 w-5" />
            </div>
            <div>
                <p className="font-medium text-slate-100">{title}</p>
                <p className="text-sm text-slate-400">{desc}</p>
            </div>
        </div>
    );
}

function BackgroundDecor() {
    return (
        <>
            {/* Gradient haze */}
            <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(ellipse_at_top_right,rgba(56,189,248,0.25),transparent_50%),radial-gradient(ellipse_at_bottom_left,rgba(14,165,233,0.25),transparent_45%)]" />

            {/* Dotted grid */}
            <svg
                className="pointer-events-none absolute inset-0 h-full w-full opacity-20"
                aria-hidden="true"
            >
                <defs>
                    <pattern id="grid" width="24" height="24" patternUnits="userSpaceOnUse">
                        <circle cx="1" cy="1" r="1" fill="currentColor" />
                    </pattern>
                </defs>
                <rect width="100%" height="100%" fill="url(#grid)" className="text-slate-800" />
            </svg>

            {/* Stylized road lanes */}
            <div className="pointer-events-none absolute -left-24 top-1/2 h-[140%] w-72 -translate-y-1/2 rotate-[18deg] bg-gradient-to-b from-white/10 via-white/5 to-transparent blur-2xl" />
            <div className="pointer-events-none absolute -right-24 top-1/2 h-[140%] w-72 -translate-y-1/2 -rotate-[18deg] bg-gradient-to-b from-sky-500/10 via-sky-400/10 to-transparent blur-2xl" />
        </>
    );
}
